INSERT INTO public.specialty_articles (id, title_en, title_uk, image_url, read_time_min) VALUES (101, 'Standards, Institutions, and Ethics', 'Standards, Institutions, and Ethics', 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/specialty-articles/encyclopedia_module_1_standards_1775401113100.png', 10);
INSERT INTO public.specialty_article_translations (article_id, language_code, title, subtitle, content_html) VALUES (101, 'uk', 'Standards, Institutions, and Ethics', '', '<div style="color: #E0E0E0; font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Helvetica, Arial, sans-serif; font-size: 16px; line-height: 1.6;"><h1 style="color: #C8A96E; font-size: 32px; font-weight: 800; margin-bottom: 32px; border-bottom: 2px solid #C8A96E; padding-bottom: 12px; letter-spacing: -0.5px;">Standards, Institutions, and Ethics</h1><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Розширене визначення Specialty Coffee</h2><p style="margin-bottom: 16px; line-height: 1.6;">Specialty Coffee — це не просто категорія товару, а замкнута екосистема контролю якості, де кожен етап виробництва спрямований на збереження та підкреслення природного генетичного потенціалу зерна.</p><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Fundamental attributes</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Attribute</h4><p style="margin-bottom: 16px;">Повна простежуваність (Traceability)</p><p style="margin-bottom: 16px; line-height: 1.6;">Можливість ідентифікувати каву до рівня конкретного лота (Micro-lot) або навіть ділянки ферми (Nano-lot). Це включає GPS-координати плантації, дату збору та точні параметри обробки.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Attribute</h4><p style="margin-bottom: 16px;">Сенсорна перевага</p><p style="margin-bottom: 16px; line-height: 1.6;">Наявність унікальних смакових дескрипторів, зумовлених теруаром, а не процесом обсмажування. Кава повинна демонструвати складну кислотність, виражену солодкість та чистий післясмак.</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Світові інституції: SCA та CQI</h2><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Organizations</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Name</h4><p style="margin-bottom: 16px;">Specialty Coffee Association (SCA)</p><p style="margin-bottom: 16px; line-height: 1.6;">Глобальна неприбуткова організація, що встановлює технічні стандарти для всієї індустрії.</p><ul style="margin-bottom: 20px; padding-left: 20px;"><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> SCA Water Standard: Специфікація хімічного складу води для заварювання (TDS, кальцієва жорсткість, лужність).</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> SCA Cupping Protocol: Суворий регламент проведення професійних дегустацій.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> SCA Green Coffee Grading: Методологія фізичного аналізу зеленого зерна перед обсмажуванням.</li></ul><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Name</h4><p style="margin-bottom: 16px;">Coffee Quality Institute (CQI)</p><p style="margin-bottom: 16px; line-height: 1.6;">Організація, що фокусується на навчанні та сертифікації спеціалістів.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Certification system</h4><h5 style="color: #C8A96E; font-size: 14px; margin-top: 20px; margin-bottom: 10px;">Program name</h5><p style="margin-bottom: 16px;">Q-Grader</p><p style="margin-bottom: 16px; line-height: 1.6;">Найвищий рівень професійної сертифікації дегустатора кави. Q-грейдери — це ''судді'', які мають право офіційно виставляти бали каві, що впливає на її ринкову вартість.</p><h5 style="color: #C8A96E; font-size: 14px; margin-top: 20px; margin-bottom: 10px;">Exam structure</h5><p style="margin-bottom: 16px;">Включає 22 тести: від калібрування сенсорних навичок до ідентифікації органічних кислот та розпізнавання дефектів обсмажування.</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Протокол оцінювання та Капінг</h2><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Cupping parameters</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Standard ratio</h4><p style="margin-bottom: 16px;">8.25 грама кави на 150 мл води.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Water temperature</h4><p style="margin-bottom: 16px;">92.2 – 94.4°C.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Grind size</h4><p style="margin-bottom: 16px;">Крупний помел (70% часток проходять через сито 20 меш).</p><ul style="margin-bottom: 20px; padding-left: 20px;"><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Fragrance/Aroma: Оцінка сухого та вологого аромату (після ламання ''кірки'').</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Flavor: Сприйняття смаку при температурі 70°C.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Acidity: Оцінка інтенсивності та характеру кислот (яблучна, лимонна, фосфорна).</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Body: Тактильне відчуття щільності та в''язкості на язику.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Uniformity: Перевірка ідентичності смаку в усіх 5 чашках одного лота.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Clean Cup: Відсутність сторонніх присмаків (земляних, хімічних, пліснявих) від початку до кінця ковтка.</li></ul><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Scoring system</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Commercial grade</h4><p style="margin-bottom: 16px;">Нижче 80 балів (використовується для мас-маркету та сублімованої кави).</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Specialty grade</h4><p style="margin-bottom: 16px;">80.00 – 84.99 (Дуже хороша кава).</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">High specialty</h4><p style="margin-bottom: 16px;">85.00 – 89.99 (Чудова кава з яскравим терруаром).</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Presidential award</h4><p style="margin-bottom: 16px;">90.00 – 100.00 (Виняткова кава, часто аукціонні лоти).</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Етична торгівля та Економіка</h2><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Models</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Type</h4><p style="margin-bottom: 16px;">Direct Trade (Пряма торгівля)</p><p style="margin-bottom: 16px; line-height: 1.6;">Модель, де обсмажувальник купує каву безпосередньо у фермера, минаючи біржових посередників. Це дозволяє виплачувати ціну, що на 50-300% вища за біржову вартість C-Market.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Type</h4><p style="margin-bottom: 16px;">Fair Trade (Справедлива торгівля)</p><p style="margin-bottom: 16px; line-height: 1.6;">Сертифікація, що гарантує мінімальну ціну захисту для фермерів та інвестиції в соціальні проєкти громад (школи, лікарні).</p><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Sustainability</h3><p style="margin-bottom: 16px;">Вимога до зменшення використання пестицидів та збереження біорізноманіття на фермах.</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"></div>');
